    90→    periods: FilterOption[];
    91→    types: FilterOption[];
    92→  };
    93→  expiringFilters: {
    94→    periods: FilterOption[];
    95→  };
    96→}
    97→
    98→export interface PointsTransaction {
    99→  id: string;
   100→  date: string;
   101→  description: string;
   102→  type: 'RECEIVED' | 'DEBIT' | 'EXPIRED' | 'REFUNDED';
   103→  amount: number;
   104→  currencyValue: number;
   105→  icon: string;
   106→  details: {
   107→    provider: string;
   108→    extraInfo: string;
   109→    fields: Array<{
   110→      label: string;
   111→      value: string;
   112→    }>;
   113→  };
   114→}
   115→
   116→export interface ExpiringPoints {
   117→  amount: number;
   118→  expirationDate: string;
   119→}
   120→
   121→export interface FilterOption {
   122→  value: string | number;
   123→  label: string;
   124→}
   125→
   126→export interface PointsExtractData {
   127→  transactions: PointsTransaction[];
   128→  expiringPoints: ExpiringPoints[];
   129→  transactionsFilters: {
   130→    periods: FilterOption[];
   131→    types: FilterOption[];
   132→  };
   133→  expiringFilters: {
   134→    periods: FilterOption[];
   135→  };
   136→}
   137→
   138→export interface ProcessedExtractData {
   139→  groupedTransactions: Array<{ date: string; items: any[] }>;
   140→  groupedExpiring: Array<{ date: string; items: any[] }>;
   141→  mappedTransactions: any[];
   142→  mappedExpiring: any[];
   143→}
   144→
   145→export interface AppliedFilters {
   146→  period?: number;
   147→  types?: string[];
   148→}
   149→
   150→export interface InitialState {
   151→  points?: number;
   152→  isLoadingBalance: boolean;
   153→  isErrorBalance: boolean;
   154→
   155→  products: PointsProduct[];
   156→  isLoadingProducts: boolean;
