   158→
   159→  extractData?: PointsExtractData;
   160→  processedExtractData?: ProcessedExtractData;
   161→  isLoadingExtract: boolean;
   162→  isErrorExtract: boolean;
   163→
   164→  appliedTransactionsFilters?: AppliedFilters;
   165→  appliedExpiringFilters?: { period?: number };
   166→
   167→  isLoadingStatement: boolean;
   168→  isErrorStatement: boolean;
   169→  data: any[];
   170→  isLoadingRescue: boolean;
   171→  isErrorRescue: boolean;
   172→  parameterization?: ParametrizationData[];
   173→  pointsQuantity: number;
   174→  isLoadingParameterization?: boolean;
