import { useCallback } from 'react';
import { useRootStore } from '../../store';
import { getPointsProducts, resetProducts } from '../services';
import { PointsProductsStatus } from '../models';

export function useProducts() {
  const { products, conversionFactor, status, error } = useRootStore(
    (state) => state.pointsProducts
  );

  const isLoading = status === PointsProductsStatus.LOADING;
  const isError = status === PointsProductsStatus.ERROR;
  const isSuccess = status === PointsProductsStatus.SUCCESS;

  const fetchProducts = useCallback(async () => {
    await getPointsProducts();
  }, []);

  const reset = useCallback(() => {
    resetProducts();
  }, []);

  return {
    products,
    conversionFactor,
    status,
    error,
    isLoading,
    isError,
    isSuccess,
    fetchProducts,
    reset,
  };
}

