  modalizeRef: RefObject<PropsModalizeRef>;
  onMenuPress: () => void;
  isMyOrders: boolean;
  setIsMyOrders: (value: boolean) => void;
}

export type ModalizeProps = { open: () => void; close: () => void } | null;

