import React, { FC, useCallback, useEffect, useState, useRef } from 'react';
import { NavigationProp, useFocusEffect, useNavigation } from '@react-navigation/native';
import { Dimensions } from 'react-native';
import { connect } from 'react-redux';

import { PointsActions } from '../../redux/ducks/points';

import theme from '../../styles/theme';
import { InformationList, InvoiceCashbackProps } from './models';
import { PropsRootStack } from '../../routes/Models';
import InvoiceCashbackView from './view';
import { bindActionCreators, Dispatch } from 'redux';
import { AppReducers } from '../../redux/reducers/Models';
import { eventScreenViewV3, eventSelectContent } from '~/constants/functions';
import BasicScreen from '../../atomic/templates/BasicScreen';
import ApiError from '../../atomic/organisms/ApiError';

const InvoiceCashbackOnboarding: FC<InvoiceCashbackProps> = ({
  route,
  pointsReducer,
  requestParameterization,
  requestPointsProducts,
}) => {
  const { width } = Dimensions.get('window');

  const [refresh, setRefresh] = useState(0);
  const hasFocused = useRef(false);
  useFocusEffect(
    React.useCallback(() => {
      if (!hasFocused.current) {
        eventScreenViewV3('desconto_fatura_onboarding', 'hub_recompensas_spmais', 'monetizacao', {
          location_1: 'monetizacao',
          location_2: 'hub_recompensas_spmais',
          location_3: 'desconto_fatura_onboarding',
        });
        hasFocused.current = true;
      }
      return () => {
        hasFocused.current = false;
      };
    }, [])
  );

  const navigation = useNavigation<NavigationProp<PropsRootStack>>();

  const conversionFactor = route?.params?.conversionFactor ?? 0;
  const campaingId = route?.params?.campaingId ?? '';
  const productCode = route?.params?.productCode ?? '';

  const pointsQuantity = pointsReducer.pointsQuantity || 0;
  const pointsPrice = (pointsReducer.points || 0) * conversionFactor;

  const handleGoBack = () => {
    navigation.goBack();
  };

  const requestAll = useCallback(() => {
    requestParameterization();
    requestPointsProducts();
  }, [requestParameterization]);

  const handleRetry = () => {
    if (pointsReducer.isErrorParameterization) {
      requestAll();
    }
  };

  const handleContinue = () => {
    navigation.navigate('InvoiceCashbackPoints', {
      conversionFactor: conversionFactor,
      campaingId: campaingId,
      productCode: productCode,
    });

    eventSelectContent({
      content_type: 'cta',
      content_id: 'continuar',
      location_1: 'monetizacao',
      location_2: 'hub_recompensas_spmais',
      location_3: 'desconto_fatura_onboarding',
    });
  };

  const invoiceList = (pts: number, price: number): InformationList[] => {
    const whiteShape = theme.colors.LIGHT_BASE_01;
    const fintechColor = theme.colors.SECONDARY_COLOR_02;

    const finalPrice = pointsQuantity * conversionFactor;
    const formattedPrice = new Intl.NumberFormat('pt-BR', {
      style: 'currency',
      currency: 'BRL',
    }).format(finalPrice);

    return [
      {
        type: 'default',
        icon: 'icon-switch-vertical',
        iconColor: fintechColor,
        iconColorShape: whiteShape,
        description: `Cada ${pointsQuantity} pontos valem ${formattedPrice} no cashback`,
      },
      {
        type: 'default',
        icon: 'icon-calendar',
        iconColor: fintechColor,
        iconColorShape: whiteShape,
        description: 'Você define quanto cashback quer aplicar na sua fatura aberta',
      },
      {
        type: 'default',
        icon: 'icon-payment-invoice',
        iconColor: fintechColor,
        iconColorShape: whiteShape,
        description: 'Se o valor for maior que o da fatura, a diferença será aplicada nas próximas',
      },
      {
        type: 'default',
        icon: 'icon-clock',
        iconColor: fintechColor,
        iconColorShape: whiteShape,
        description: 'O cashback acontece em até 72h',
      },
    ];
  };

  const finalPrice = pointsPrice || 0;

  const items: InformationList[] = invoiceList
    ? invoiceList(Math.trunc(Number(pointsReducer.points)) ?? 0, finalPrice).map((item) => ({
        icon: item.icon,
        iconColor: item.iconColor,
        description: item.description,
        iconColorShape: item.iconColorShape,
        type: item.type,
      }))
    : [];

  useEffect(() => {
    requestParameterization();
  }, [refresh]);
  console.log(pointsReducer, 'points-reducer')

  if (pointsReducer.isErrorParameterization) {
    return (
      <BasicScreen
        leftIconOnPress={handleGoBack}
        title="Cashback na fatura"
        errorButtonOnPress={handleRetry}
      >
        <ApiError onPress={handleRetry} />
      </BasicScreen>
    );
  }
  return (
    <InvoiceCashbackView
      handleGoBack={handleGoBack}
      handleContinue={handleContinue}
      handleRetry={handleRetry}
      items={items}
      hasError={pointsReducer.isErrorBalance}
      hasLoading={pointsReducer.isLoadingBalance}
      cashbackInvoiceList={invoiceList()}
      pts={pointsReducer.points || 0}
      price={pointsPrice}
      pointsQuantity={pointsQuantity}
      conversionFactor={conversionFactor}
      width={width}
      isLoadingParameterization={pointsReducer?.isLoadingParameterization}
    />
  );
};

export const mapStateToProps = ({ pointsReducer }: AppReducers) => ({
  pointsReducer,
});

export const mapDispatchToProps = (dispatch: Dispatch) => {
  return bindActionCreators(
    {
      ...PointsActions,
    },
    dispatch
  );
};

export default connect(mapStateToProps, mapDispatchToProps)(InvoiceCashbackOnboarding);

